import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Weather condition to icon/emoji mapping
// Weather condition to icon/emoji mapping with comprehensive coverage
const getWeatherIcon = useCallback((condition: string): string => {
  const conditionLower = condition.toLowerCase();
  const iconMap: Record<string, string> = {
    'sunny': '☀️',
    'clear': '🌙',
    'cloudy': '☁️',
    'overcast': '☁️',
    'scattered clouds': '⛅',
    'partly cloudy': '⛅',
    'rainy': '🌧️',
    'light rain': '🌧️',
    'heavy rain': '🌧️',
    'drizzle': '🌦️',
    'snowy': '❄️',
    'mist': '🌫️',
    'stormy': '⛈️',
    'thunderstorm': '⛈️',
    'windy': '💨',
  };
  return iconMap[conditionLower] || '❓';
}, []);

  // Format temperature with unit
  const tempDisplay = useMemo(() => `${props.temperature}°${props.unit || 'C'}`, [props.temperature, props.unit]);

  // Format forecast temperature with unit
  const forecastTempDisplay = useCallback((temp: number | undefined) => {
    return temp !== undefined ? `${temp}°${props.unit || 'C'}` : '—';
  }, [props.unit]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Header with city name */}
        <Heading level={1} align="center" color="var(--ggui-color-onSurface)">{props.city}</Heading>

        {/* Current weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-8)" radius="lg" style={{ maxWidth: '400px', width: '100%' }}>
          <Stack gap="var(--ggui-spacing-6)" align="center">
            {/* Temperature and condition */}
            <Stack gap="var(--ggui-spacing-4)" align="center">
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">{tempDisplay}</Text>
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center" justify="center">
                 <Text size="2xl">{getWeatherIcon(props.condition)}</Text>
                <Text size="lg" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
              </Stack>
            </Stack>

            <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" />

            {/* Humidity and wind speed */}
            <Stack direction="horizontal" gap="var(--ggui-spacing-6)" justify="center" align="stretch" style={{ width: '100%' }}>
              <Stack gap="var(--ggui-spacing-2)" align="center" style={{ flex: 1 }}>
                <Icon name="droplets" size={20} color="var(--ggui-color-primary-600)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-2)" align="center" style={{ flex: 1 }}>
                <Icon name="wind" size={20} color="var(--ggui-color-primary-600)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed}</Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-day forecast strip */}
        {props.forecast && props.forecast.length > 0 && (
          <Box style={{ width: '100%' }}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ marginBottom: 'var(--ggui-spacing-4)', display: 'block' }}>5-Day Forecast</Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center" justify="start" wrap={true} style={{ textAlign: 'center' }}>
              {props.forecast.map((day, idx) => (
                <Card key={idx} shadow="sm" padding="var(--ggui-spacing-4)" radius="md" style={{ flex: '1 1 auto', minWidth: '80px', maxWidth: '100px' }}>
                  <Stack gap="var(--ggui-spacing-2)" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurface)" size="sm">{day.day || `Day ${idx + 1}`}</Text>
                    <Text size="lg">{getWeatherIcon(day.condition || day.icon || 'Sunny')}</Text>
                    <Stack direction="horizontal" gap="var(--ggui-spacing-1)" justify="center" style={{ width: '100%' }}>
                      <Text size="xs" weight="semibold" color="var(--ggui-color-primary-600)">{forecastTempDisplay(day.high)}</Text>
                      <Text size="xs" color="var(--ggui-color-onSurfaceVariant)">{forecastTempDisplay(day.low)}</Text>
                    </Stack>
                  </Stack>
                </Card>
              ))}
            </Stack>
          </Box>
        )}

      </Stack>
    </Container>
  );
}

