import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // Form state
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helpers
  const isValidEmail = (value: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  };

  const isStep1Valid = (): boolean => {
    return name.trim().length > 0 && isValidEmail(email);
  };

  const canProceedToNextStep = (): boolean => {
    if (step === 1) return isStep1Valid();
    return true;
  };

  const handleNext = (): void => {
    if (step < 5 && canProceedToNextStep()) {
      setStep(step + 1);
    }
  };

  const handleBack = (): void => {
    if (step > 1) {
      setStep(step - 1);
    }
  };

  const handleSubmit = (): void => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    });
  };

  const satisfactionOptions = props.satisfactionLabels.map((label, idx) => ({
    value: String(idx + 1),
    label,
  }));

  const featureCheckboxes = props.featureOptions.map((option) => ({
    label: option,
    checked: features.includes(option),
  }));

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="center">
        {/* Progress Bar */}
        <Box width="100%" maxWidth="600px">
          <Stack gap="var(--ggui-spacing-2)" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {step} of 4
            </Text>
            <Progress value={step} max={4} variant="default" size="md" />
          </Stack>
        </Box>

        {/* Step 1: Name & Email */}
        {step === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" borderRadius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Contact Information
              </Heading>
              <Input
                label="Name"
                value={name}
                onChange={setName}
                placeholder="John Doe"
                required
                error={name.trim().length === 0 ? 'Name is required' : ''}
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                placeholder="john@example.com"
                required
                error={
                  email.trim().length === 0
                    ? 'Email is required'
                    : !isValidEmail(email)
                    ? 'Please enter a valid email address'
                    : ''
                }
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {step === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" borderRadius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Satisfaction Rating
              </Heading>
              <RadioGroup
                label="How satisfied are you with our service?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {step === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" borderRadius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Features of Interest
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Which features are you most interested in?
              </Text>
              <Stack gap="var(--ggui-spacing-4)">
                {props.featureOptions.map((option) => (
                  <Checkbox
                    key={option}
                    label={option}
                    checked={features.includes(option)}
                    onChange={(checked) => {
                      setFeatures(
                        checked
                          ? [...features, option]
                          : features.filter((f) => f !== option)
                      );
                    }}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {step === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" borderRadius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Additional Comments
              </Heading>
              <TextArea
                label="Comments"
                value={comments}
                onChange={setComments}
                placeholder="Tell us what you think..."
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Final Review */}
        {step === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" borderRadius="lg" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Review Your Answers
              </Heading>
              <Stack gap="var(--ggui-spacing-4)">
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Contact Information
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)">
                      <strong>Name:</strong> {name}
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)">
                      <strong>Email:</strong> {email}
                    </Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Satisfaction Rating
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)">
                      {props.satisfactionLabels[parseInt(satisfaction, 10) - 1]} ({satisfaction}/5)
                    </Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Features of Interest
                    </Text>
                    {features.length > 0 ? (
                      <Stack gap="var(--ggui-spacing-2)">
                        {features.map((feature) => (
                          <Text key={feature} variant="body" color="var(--ggui-color-onSurface)">
                            • {feature}
                          </Text>
                        ))}
                      </Stack>
                    ) : (
                      <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                        None selected
                      </Text>
                    )}
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Comments
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)">
                      {comments || '(No comments provided)'}
                    </Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Box width="100%" maxWidth="600px">
          <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="between" align="center">
            <Button
              variant="outline"
              size="md"
              onClick={handleBack}
              disabled={step === 1}
            >
              Back
            </Button>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              {step < 5 && (
                <Button
                  variant="primary"
                  size="md"
                  onClick={handleNext}
                  disabled={!canProceedToNextStep()}
                >
                  Next
                </Button>
              )}
              {step === 5 && (
                <Button
                  variant="primary"
                  size="md"
                  onClick={handleSubmit}
                >
                  Submit
                </Button>
              )}
            </Stack>
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}
}

