// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string; priority?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // State for add task forms (per column)
  const [addingTaskColumn, setAddingTaskColumn] = useState<string | null>(null);
  const [newTaskTitles, setNewTaskTitles] = useState<Record<string, string>>({});
  const [newTaskPriorities, setNewTaskPriorities] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  // Merge initial tasks with stream updates
  const allTasks = useMemo(() => {
    const tasksMap = new Map((props.tasks || []).map(t => [t.id, t]));
    (taskChanged.all || []).forEach(event => {
      if (event?.task?.id) {
        const streamTask = event.task;
        if (event.action === 'delete') {
          tasksMap.delete(streamTask.id);
        } else {
          tasksMap.set(streamTask.id, { ...tasksMap.get(streamTask.id), ...streamTask });
        }
      }
    });
    return Array.from(tasksMap.values());
  }, [props.tasks, taskChanged.all]);

  // Compute tasks per column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof allTasks> = {};
    (props.columns || []).forEach(col => {
      grouped[col.id || ''] = [];
    });
    allTasks.forEach(task => {
      const colId = task.column || '';
      if (colId in grouped) {
        grouped[colId].push(task);
      }
    });
    return grouped;
  }, [allTasks, props.columns]);

  // Compute totals
  const totalTasks = allTasks.length;
  const completedTasks = (tasksByColumn['done'] || []).length;

  // Handlers
  const handleAddTask = useCallback((columnId: string) => {
    const title = newTaskTitles[columnId] || '';
    const priority = newTaskPriorities[columnId] || 'low';
    if (title.trim()) {
      const newId = `task-${Date.now()}`;
      taskUpdate({
        action: 'create',
        taskId: newId,
        data: { column: columnId, title, priority }
      });
      setNewTaskTitles(prev => ({ ...prev, [columnId]: '' }));
      setNewTaskPriorities(prev => ({ ...prev, [columnId]: 'low' }));
      setAddingTaskColumn(null);
    }
  }, [newTaskTitles, newTaskPriorities, taskUpdate]);

  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    taskUpdate({
      action: 'move',
      taskId,
      data: { column: targetColumn }
    });
  }, [taskUpdate]);

  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    taskUpdate({
      action: 'edit',
      taskId,
      data: { column: '', title: newTitle }
    });
    setEditingTaskId(null);
    setEditingTitle('');
  }, [taskUpdate]);

  // Render task card
  const renderTaskCard = (task: typeof allTasks[0], columnId: string) => {
    const isEditing = editingTaskId === task.id;
    const priorityVariant = task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'default';
    const moveOptions = (props.columns || []).filter(col => col.id !== columnId).map(col => ({
      value: col.id || '',
      label: col.name || ''
    }));

    return (
      <Card key={task.id} shadow="sm" padding="var(--ggui-spacing-4)" radius="md" style={{ marginBottom: 'var(--ggui-spacing-2)' }}>
        <Stack gap="var(--ggui-spacing-2)" style={{ alignItems: 'flex-start' }}>
          {isEditing ? (
            <Stack gap="var(--ggui-spacing-2)" style={{ width: '100%' }}>
              <Input
                label="Edit title"
                value={editingTitle}
                onChange={setEditingTitle}
              />
              <Row gap="var(--ggui-spacing-2)" style={{ justifyContent: 'flex-end' }}>
                <Button size="xs" variant="ghost" onClick={() => {
                  setEditingTaskId(null);
                  setEditingTitle('');
                }}>
                  Cancel
                </Button>
                <Button size="xs" variant="primary" onClick={() => handleEditTask(task.id || '', editingTitle)}>
                  Save
                </Button>
              </Row>
            </Stack>
          ) : (
            <Stack gap="var(--ggui-spacing-2)" style={{ width: '100%', alignItems: 'flex-start' }}>
              <Row gap="var(--ggui-spacing-2)" style={{ alignItems: 'center', width: '100%' }}>
                <Text variant="body" weight="medium" style={{ flex: 1, color: 'var(--ggui-color-onSurface)' }}>
                  {task.title}
                </Text>
                <Button size="xs" variant="ghost" onClick={() => {
                  setEditingTaskId(task.id || '');
                  setEditingTitle(task.title || '');
                }}>
                  <Icon name="edit" size={16} />
                </Button>
              </Row>
            </Stack>
          )}
          <Row gap="var(--ggui-spacing-2)" style={{ alignItems: 'center', justifyContent: 'space-between', width: '100%' }}>
