          <Row gap="var(--ggui-spacing-2)" style={{ width: '100%', justifyContent: 'flex-end' }}>
            {moveOptions.length > 0 && (
              <Select
                label="Move to"
                value=""
                onChange={(newCol) => {
                  if (newCol) handleMoveTask(task.id || '', newCol);
                }}
                options={moveOptions}
                placeholder="Move..."
                size="sm"
              />
            )}
          </Row>
        </Stack>
      </Card>
    );
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
          <Row gap="var(--ggui-spacing-4)" style={{ justifyContent: 'center', alignItems: 'center' }}>
            <Text variant="body" weight="semibold" color="var(--ggui-color-primary-900)">
              Total Tasks: {totalTasks}
            </Text>
            <Text variant="body" weight="semibold" color="var(--ggui-color-success-700)">
              Completed: {completedTasks}
            </Text>
          </Row>
        </Box>

        {/* Kanban Columns */}
        <Row gap="var(--ggui-spacing-4)" style={{ alignItems: 'flex-start' }}>
          {(props.columns || []).map(column => {
            const colId = column.id || '';
            const colTasks = tasksByColumn[colId] || [];
            const isAddingInThisColumn = addingTaskColumn === colId;

            return (
              <Card key={colId} shadow="md" padding="var(--ggui-spacing-4)" radius="lg" style={{ flex: 1, minWidth: '300px' }}>
