                  <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                  {isAddingInThisColumn ? (
                    <Stack gap="var(--ggui-spacing-2)">
                      <Input
                        label="Task title"
                        placeholder="Enter task title"
                        value={newTaskTitles[colId] || ''}
                        onChange={(val) => setNewTaskTitles(prev => ({ ...prev, [colId]: val }))}
                      />
                      <Select
                        label="Priority"
                        value={newTaskPriorities[colId] || 'low'}
                        onChange={(val) => setNewTaskPriorities(prev => ({ ...prev, [colId]: val as 'low' | 'medium' | 'high' }))}
