                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' }
                        ]}
                      />
                      <Row gap="var(--ggui-spacing-2)" style={{ justifyContent: 'flex-end' }}>
                        <Button size="sm" variant="ghost" onClick={() => {
                          setAddingTaskColumn(null);
                          setNewTaskTitles(prev => ({ ...prev, [colId]: '' }));
                        }}>
                          Cancel
                        </Button>
                        <Button size="sm" variant="primary" onClick={() => handleAddTask(colId)}>
                          Add Task
                        </Button>
                      </Row>
                    </Stack>
                  ) : (
                    <Button
                      size="sm"
                      variant="outline"
                      fullWidth
                      onClick={() => setAddingTaskColumn(colId)}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

