// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





export default function Component(props: Props) {
  // Wire hooks (none needed for this component)

  // State for search and selected element
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by search query (case-insensitive, name or symbol)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories and their colors
  const categoryColors = useMemo(() => {
    const colors: Record<string, string> = {
      'alkali-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-200, #bae6fd)',
      'transition-metal': 'var(--ggui-color-warning-100, #fef3c7)',
      'lanthanide': 'var(--ggui-color-success-100, #dcfce7)',
      'actinide': 'var(--ggui-color-error-100, #fee2e2)',
      'post-transition-metal': 'var(--ggui-color-info-100, #cffafe)',
      'metalloid': 'var(--ggui-color-primary-50, #f0f9ff)',
      'nonmetal': 'var(--ggui-color-primary-300, #7dd3fc)',
      'halogen': 'var(--ggui-color-warning-200, #fde68a)',
      'noble-gas': 'var(--ggui-color-success-200, #bbf7d0)',
    };
    return colors;
  }, []);

  // Get all unique categories from elements
  const allCategories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  // Get background color for element based on category
  const getElementColor = useCallback((element: typeof props.elements[0]): string => {
    if (!element.category) return 'var(--ggui-color-surface, #ffffff)';
    return categoryColors[element.category] || 'var(--ggui-color-surface, #ffffff)';
  }, [categoryColors]);

  // Check if element is visible in filtered results
  const isElementVisible = useCallback((element: typeof props.elements[0]): boolean => {
    return filteredElements.some(el => el.symbol === element.symbol);
  }, [filteredElements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Interactive periodic table. Search by name or symbol, click elements for details.
          </Text>
        </Stack>

        {/* Search Input */}
        <Input
          label="Search elements"
          placeholder="Type element name or symbol (e.g., 'gold' or 'Au')"
          value={searchQuery}
          onChange={setSearchQuery}
          type="text"
        />

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="none" border={true} radius="md">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label">Legend</Text>
            <Row gap="var(--ggui-spacing-4)" wrap={true} align="center">
              {allCategories.map(cat => (
                <Box key={cat} padding="var(--ggui-spacing-2)" borderRadius="var(--ggui-shape-radius-sm, 4px)" style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2)' }}>
                  <Box style={{
                    width: '16px',
                    height: '16px',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    backgroundColor: categoryColors[cat] || 'var(--ggui-color-surface, #ffffff)',
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }} />
                  <Text variant="caption">{cat.replace(/-/g, ' ')}</Text>
                </Box>
              ))}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, 1fr)',
          gap: 'var(--ggui-spacing-2, 8px)',
          padding: 'var(--ggui-spacing-4, 16px)',
          border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        }}>
          {props.elements.map((element, idx) => {
            const row = element.row || 0;
            const col = element.col || 0;
            const isVisible = isElementVisible(element);
            const bgColor = getElementColor(element);
            const isSelected = selectedElement?.symbol === element.symbol;

            if (!isVisible) return null;

            return (
              <Card
                key={`${element.symbol}-${idx}`}
                padding="var(--ggui-spacing-3)"
                shadow="sm"
                radius="md"
                border={true}
                as={Clickable}
                onClick={() => setSelectedElement(element)}
                style={{
                  gridRow: row,
                  gridColumn: col,
                  cursor: 'pointer',
                  backgroundColor: bgColor,
                  borderColor: isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)',
                  borderWidth: isSelected ? '2px' : '1px',
                  transition: 'all 0.2s ease-in-out',
                  opacity: isVisible ? 1 : 0.3,
                }}
              >
                <Stack gap="var(--ggui-spacing-1)" align="center">
                  {/* Atomic Number */}
                  {element.atomicNumber !== undefined && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="left" style={{ alignSelf: 'flex-start' }}>
                      {element.atomicNumber}
                    </Text>
                  )}

                  {/* Symbol */}
                  <Text
                    variant="body"
                    weight="bold"
                    size="2xl"
                    color="var(--ggui-color-onSurface, #18181b)"
                    align="center"
                  >
                    {element.symbol}
                  </Text>

                  {/* Name (if space allows) */}
                  {element.name && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                      {element.name}
                    </Text>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Row gap="var(--ggui-spacing-4)" align="center">
                <Box style={{
                  width: '80px',
                  height: '80px',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  backgroundColor: getElementColor(selectedElement),
                  border: '2px solid var(--ggui-color-primary-600, #0284c7)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                }}>
                  <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {selectedElement.symbol}
                  </Text>
                </Box>
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Badge variant="default">{selectedElement.category || 'Unknown'}</Badge>
                </Stack>
              </Row>

              <Divider />

              {/* Details Grid */}
              <Row gap="var(--ggui-spacing-8)" wrap={true}>
                {selectedElement.atomicNumber !== undefined && (
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Atomic Number
                    </Text>
                    <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {selectedElement.atomicNumber}
                    </Text>
                  </Box>
                )}
                {selectedElement.atomicWeight !== undefined && (
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Atomic Weight
                    </Text>
                    <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {selectedElement.atomicWeight.toFixed(2)}
                    </Text>
                  </Box>
                )}
                {selectedElement.row !== undefined && (
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Period
                    </Text>
                    <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {selectedElement.row}
                    </Text>
                  </Box>
                )}
                {selectedElement.col !== undefined && (
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Group
                    </Text>
                    <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {selectedElement.col}
                    </Text>
                  </Box>
                )}
              </Row>

              {/* Close Button */}
              <Button variant="ghost" onClick={() => setSelectedElement(null)}>
                Close Details
              </Button>
            </Stack>
          </Card>
        )}

        {/* No Results Message */}
        {searchQuery && filteredElements.length === 0 && (
          <Alert variant="info" title="No elements found">
            No elements match your search query. Try a different name or symbol.
          </Alert>
        )}
      </Stack>
    </Container>
  );
}
}

