import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Computed values
  const isOutOfStock = useMemo(() => props.product.stock === 0, [props.product.stock]);
  const isLowStock = useMemo(() => props.product.stock !== undefined && props.product.stock > 0 && props.product.stock < 5, [props.product.stock]);
  const formattedPrice = useMemo(() => {
    if (!props.product.price || !props.product.currency) return '';
    return `${props.product.currency}${props.product.price.toFixed(2)}`
  }, [props.product.price, props.product.currency]);

  // Handlers
  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  const handleQuantityChange = useCallback((newQty: number) => {
    const maxQty = props.product.stock || 1;
    const clampedQty = Math.max(1, Math.min(newQty, maxQty));
    setQuantity(clampedQty);
  }, [props.product.stock]);

  // Helper to render star rating
  const renderStars = (rating: number | undefined) => {
    if (!rating) return null;
    return (
      <Row gap={4} align="center">
        {Array.from({ length: 5 }).map((_, i) => (
          <Icon key={i} name={i < Math.floor(rating) ? 'star' : 'star'} size={16} color={i < Math.floor(rating) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outlineVariant, #e4e4e7)'} />
        ))}
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{rating.toFixed(1)} ({props.product.reviewCount || 0})</Text>
      </Row>
    );
  };

  // Tab items
  const tabItems = useMemo(() => [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
          {props.product.description || 'No description available'}
        </Text>
      )
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
        <Stack gap={12}>
          {props.product.specifications.map((spec: any, idx: number) => (
            <Row key={idx} justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{spec.key || 'Key'}</Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{spec.value || 'Value'}</Text>
            </Row>
          ))}
        </Stack>
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No specifications available</Text>
      )
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
        <Stack gap={16}>
          {props.product.reviews.map((review: any, idx: number) => (
            <Card key={idx} padding={16} radius="md" border>
              <Stack gap={8}>
                <Row justify="between" align="center">
                  <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{review.author || 'Anonymous'}</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{review.date ? new Date(review.date).toLocaleDateString() : ''}</Text>
                </Row>
                <Row gap={4} align="center">
                  {Array.from({ length: 5 }).map((_, i) => (
                    <Icon key={i} name={i < (review.rating || 0) ? 'star' : 'star'} size={14} color={i < (review.rating || 0) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outlineVariant, #e4e4e7)'} />
                  ))}
                </Row>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{review.text || ''}</Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet</Text>
      )
    }
  ], [props.product.description, props.product.specifications, props.product.reviews, props.product.reviewCount]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap={32}>
        {/* TOP SECTION: Image, Title, Price, Rating, Stock */}
        <Stack gap={24}>
          <Row gap={24} align="start" wrap>
            {/* Product Image Placeholder */}
            <Box background="var(--ggui-color-primary-100, #e0f2fe)" padding="var(--ggui-spacing-8)" borderRadius={8} style={{ minWidth: '300px', width: '100%', maxWidth: '400px', aspectRatio: '1/1', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <Stack align="center" justify="center">
                <Icon name="image" size={48} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="body" color="var(--ggui-color-primary-700, #0369a1)">{props.product.name || 'Product Image'}</Text>
              </Stack>
            </Box>

            {/* Product Details */}
            <Stack gap={16} style={{ flex: 1, minWidth: '300px' }}>
              <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">{props.product.name || 'Unnamed Product'}</Heading>

              {/* Price */}
              <Text size="2xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">{formattedPrice}</Text>

              {/* Rating Stars */}
              {renderStars(props.product.rating)}

              {/* Stock Status Badge */}
              <div>
                {isOutOfStock ? (
                  <Badge variant="error">Out of Stock</Badge>
                ) : isLowStock ? (
                  <Badge variant="warning">Low Stock</Badge>
                ) : (
                  <Badge variant="success">In Stock</Badge>
                )}
              </div>
            </Stack>
          </Row>
        </Stack>

        {/* MIDDLE SECTION: Tabs */}
        <Tabs items={tabItems} activeKey={activeTab} onChange={setActiveTab} variant="line" />

        {/* BOTTOM SECTION: Quantity Selector & Add to Cart */}
        <Card padding={24} shadow="md" radius="lg">
          <Stack gap={16}>
            {/* Quantity Selector */}
            <Stack gap={12}>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Quantity</Text>
              <Row gap={12} align="center">
                <Button
                  variant="outline"
                  size="md"
                  onClick={() => handleQuantityChange(quantity - 1)}
                  disabled={quantity <= 1}
                >
                  −
                </Button>
                <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" style={{ minWidth: '40px', textAlign: 'center' }}>{quantity}</Text>
                <Button
                  variant="outline"
                  size="md"
                  onClick={() => handleQuantityChange(quantity + 1)}
                  disabled={quantity >= (props.product.stock || 1)}
                >
                  +
                </Button>
              </Row>
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              fullWidth
              disabled={isOutOfStock}
              onClick={handleAddToCart}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
}

