// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State management
  const [messageText, setMessageText] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [typingIndicators, setTypingIndicators] = useState<Record<string, boolean>>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Sync incoming messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages(prev => [...prev, message.latest]);
    }
  }, [message.latest]);

  // Sync typing indicator from stream
  // Sync typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      setTypingIndicators(prev => {
        const updated = { ...prev };
        if (typing.latest.active && typing.latest.sender) {
          updated[typing.latest.sender] = true;
        } else if (typing.latest.sender) {
          delete updated[typing.latest.sender];
        }
        return updated;
      });
    }
  }, [typing.latest]);

  // Auto-scroll to bottom when new messages arrive
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  // Handle message send
  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: messageText, timestamp });
      setMessageText('');
    }
  }, [messageText, sendMessage]);

  // Handle Enter key press
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Check if message is from current user
  const isCurrentUserMessage = useCallback((sender?: string) => {
    return sender === props.currentUser;
  }, [props.currentUser]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" radius="lg" padding="var(--ggui-spacing-6)" border={true}>
        <Stack gap={16}>
          {/* Header */}
          <Stack gap={12}>
            <Row gap={12} align="center" justify="between">
              <Heading level={2}>{props.title}</Heading>
              <Badge variant="default" size="sm">
                {props.participantCount} participants
              </Badge>
            </Row>
            {Object.keys(typingIndicators).length > 0 && (
              <Stack gap={4}>
                {Object.keys(typingIndicators).map((sender) => (
                  <Text key={sender} variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {sender} is typing
                    <span style={{ display: 'inline-block', marginLeft: '4px' }}>
                      <span style={{ animation: 'blink 0.6s infinite' }}>.</span>
                      <span style={{ animation: 'blink 0.6s infinite', animationDelay: '0.2s' }}>.</span>
                      <span style={{ animation: 'blink 0.6s infinite', animationDelay: '0.4s' }}>.</span>
                    </span>
                  </Text>
                ))}
              </Stack>
            )}
          </Stack>

          <Divider orientation="horizontal" margin={12} />

          {/* Message List */}
          <Box
            style={{
              overflowY: 'auto',
              maxHeight: '400px',
              padding: 'var(--ggui-spacing-4)',
              backgroundColor: 'var(--ggui-color-surface, #fafafa)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
            }}
          >
            <Stack gap={12}>
              {allMessages.length === 0 ? (
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                  No messages yet. Start the conversation!
                </Text>
              ) : (
                allMessages.map((msg, index) => {
                  const isCurrent = isCurrentUserMessage(msg.sender);
                  const previousMsg = index > 0 ? allMessages[index - 1] : null;
                  const sameAsPrevious = previousMsg?.sender === msg.sender;

                  return (
                    <Box key={index}>
                      {!sameAsPrevious && msg.sender && (
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ marginBottom: '4px' }}>
                          {msg.sender}
                        </Text>
                      )}
                      <Box
                        style={{
                          display: 'flex',
                          justifyContent: isCurrent ? 'flex-end' : 'flex-start',
                          marginTop: sameAsPrevious ? '2px' : '0px',
                        }}
                      >
                        <Card
                          padding="var(--ggui-spacing-4)"
                          shadow="sm"
                          radius="lg"
                          style={{
                            backgroundColor: isCurrent
                              ? 'var(--ggui-color-primary-600, #0284c7)'
                              : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                            maxWidth: '70%',
                            wordWrap: 'break-word',
                          }}
                        >
                          <Stack gap={4}>
                            <Text
                              variant="body"
                              color={isCurrent ? 'var(--ggui-color-onPrimary, #ffffff)' : 'var(--ggui-color-onSurface, #18181b)'}
                            >
                              {msg.text}
                            </Text>
                            {msg.timestamp && (
                              <Text
                                variant="caption"
                                color={isCurrent ? 'var(--ggui-color-onPrimary, rgba(255, 255, 255, 0.7))' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                                align="right"
                              >
                                {new Date(msg.timestamp).toLocaleTimeString([], {
                                  hour: '2-digit',
                                  minute: '2-digit',
                                })}
                              </Text>
                            )}
                          </Stack>
                        </Card>
                      </Box>
                    </Box>
                  );
                })
              )}
              <div ref={messagesEndRef} style={{ height: 0 }} />
            </Stack>
          </Box>

          <Divider orientation="horizontal" margin={12} />

          {/* Message Input */}
          <Stack gap={12}>
            <TextArea
              label="Message"
              value={messageText}
              onChange={setMessageText}
              placeholder="Type your message here... (Enter to send, Shift+Enter for new line)"
              rows={3}
            />
            <Row gap={8} justify="end">
              <Button
                variant="primary"
                size="md"
                disabled={!messageText.trim()}
                onClick={handleSendMessage}
              >
                Send
              </Button>
            </Row>
          </Stack>
        </Stack>
      </Card>
      <style>{`
        @keyframes blink {
          0%, 20%, 50%, 100% { opacity: 1; }
          40% { opacity: 0.5; }
          60% { opacity: 0.7; }
        }
      `}</style>
    </Container>
  );
}

