// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  // State: merge live updates with initial stocks data
  const [displayStocks, setDisplayStocks] = useState(() =>
    props.stocks.map(stock => ({ ...stock, symbol: stock.symbol || '', name: stock.name || '', price: stock.price ?? 0, change: stock.change ?? 0, changePercent: stock.changePercent ?? 0 }))
  );
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [flashingSymbol, setFlashingSymbol] = useState<string | null>(null);

  // Apply live price updates from stream
  useEffect(() => {
    if (priceUpdate.latest) {
      const symbol = priceUpdate.latest.symbol;
      setFlashingSymbol(symbol || null);
      setDisplayStocks(prev =>
        prev.map(stock =>
          stock.symbol === symbol
            ? {
              ...stock,
              price: priceUpdate.latest.price ?? stock.price,
              change: priceUpdate.latest.change ?? stock.change,
              changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
            }
            : stock
        )
      );
      setLastUpdated(new Date());
      // Clear flash animation after 600ms
      const timer = setTimeout(() => setFlashingSymbol(null), 600);
      return () => clearTimeout(timer);
    }
  }, [priceUpdate.latest]);

  // Update timestamp from marketStatus events
  useEffect(() => {
    if (marketStatus.latest?.timestamp) {
      setLastUpdated(new Date(marketStatus.latest.timestamp));
    }
  }, [marketStatus.latest]);

  // Format price with 2 decimals
  const formatPrice = useCallback((price: number) => price.toFixed(2), []);

  // Format change percent with 2 decimals and arrow
  const formatChangePercent = useCallback((changePercent: number) => ({
    text: Math.abs(changePercent).toFixed(2),
    arrow: changePercent > 0 ? '▲' : changePercent < 0 ? '▼' : '',
  }), []);

  // Get color based on change
  const getChangeColor = useCallback((change: number) => {
    if (change > 0) return 'var(--ggui-color-success-600, #16a34a)';
    if (change < 0) return 'var(--ggui-color-error-600, #dc2626)';
    return 'var(--ggui-color-onSurfaceVariant, #52525b)';
  }, []);

  // Get border color based on change
  const getChangeBorder = useCallback((change: number) => {
    if (change > 0) return 'solid var(--ggui-color-success-600, #16a34a)';
    if (change < 0) return 'solid var(--ggui-color-error-600, #dc2626)';
    return 'solid var(--ggui-color-outline, #d4d4d8)';
  }, []);

  return (
    <>
      <style>{`
        @keyframes ggui-stock-flash {
          0% { background-color: var(--ggui-color-primary-100, #e0f2fe); }
          100% { background-color: transparent; }
        }
      `}</style>
      <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-6)">
          {/* Header with title and last updated timestamp */}
          <Box paddingY="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={1}>Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {lastUpdated.toLocaleTimeString()}
              </Text>
            </Stack>
          </Box>

          {/* Responsive grid of stock cards */}
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
              gap: 'var(--ggui-spacing-6, 24px)',
            } as React.CSSProperties}
          >
            {displayStocks.length > 0 ? (
              displayStocks.map(stock => {
                const changeColor = getChangeColor(stock.change);
                const changeBorder = getChangeBorder(stock.change);
                const changePercent = formatChangePercent(stock.changePercent);

                return (
                  <Card
                    key={stock.symbol}
                    padding="var(--ggui-spacing-5)"
                    shadow="md"
                    border={true}
                    style={{
                      borderColor: changeColor,
                      borderWidth: '2px',
                      ...(flashingSymbol === stock.symbol ? { animation: 'ggui-stock-flash 0.6s ease-out' } : {})
                    }}
                    <Stack gap='var(--ggui-spacing-3)'>
                      {/* Ticker symbol - large, bold */}
                      <Text variant="label" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {stock.symbol}
                      </Text>

                      {/* Company name */}
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name}
                      </Text>

                      {/* Current price formatted with 2 decimals */}
                      <Text variant="body" size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        ${formatPrice(stock.price)}
                      </Text>

                      {/* Change amount */}
                      <Text variant="body" color={changeColor}>
                        {stock.change > 0 ? '+' : ''}{formatPrice(stock.change)}
                      </Text>

                      {/* Change percentage with arrow */}
                      <Row gap='var(--ggui-spacing-1)' align="center">
                        <Text variant="label" color={changeColor} weight="semibold">
                          {changePercent.arrow} {changePercent.text}%
                        </Text>
                      </Row>
                    </Stack>
                  </Card>
                );
              })
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stocks available
              </Text>
            )}
          </Box>
        </Stack>
      </Container>
    </>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // Wire hooks
  const complete = useAction<ActionCompletePayload>('complete');

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar ?? '');
  const [role, setRole] = useState(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? false);
  const [theme, setTheme] = useState(props.initialProfile?.theme ?? 'light');
  const [emailError, setEmailError] = useState('');
  const [nameError, setNameError] = useState('');

  // Validation helpers
  const validateEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  const validateStep1 = useCallback((): boolean => {
    let isValid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Please enter a valid email address');
      isValid = false;
    } else {
      setEmailError('');
    }
    return isValid;
  }, [name, email, validateEmail]);

  // Handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      if (!validateStep1()) return;
    }
    setCurrentStep(currentStep + 1);
  }, [currentStep, validateStep1]);

  const handleBack = useCallback(() => {
    setCurrentStep(currentStep - 1);
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    complete({
      name,
      email,
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [complete, name, email, avatar, role, emailNotifications, theme]);

  // Computed values
  const isStep1Valid = useMemo(() => name.trim() && email.trim() && validateEmail(email), [name, email, validateEmail]);
  const avatarsList = useMemo(() => props.avatarOptions || [], [props.avatarOptions]);
  const rolesList = useMemo(() => (props.roleOptions || []).map(opt => ({ value: opt, label: opt })), [props.roleOptions]);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header with progress indicator */}
        <Stack gap="var(--ggui-spacing-4)" align="center">
          <Heading level={2}>Profile Setup</Heading>
          <Stack gap="var(--ggui-spacing-2)" align="center">
            <Text variant="label">Step {currentStep} of 3</Text>
            <Progress value={currentStep} max={3} size="md" />
          </Stack>
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Stack gap="var(--ggui-spacing-6)">
            <Card shadow="md" padding="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Step 1: Profile Setup</Heading>
                <Stack gap="var(--ggui-spacing-4)">
                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    placeholder="Enter your full name"
                    error={nameError}
                    required
                  />
                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={setEmail}
                    placeholder="Enter your email address"
                    error={emailError}
                    required
                  />
                </Stack>

                {/* Avatar selection */}
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {avatarsList.map((avatarEmoji) => (
                      <Box
                        key={avatarEmoji}
                        as={Clickable}
                        onClick={() => setAvatar(avatarEmoji)}
                        padding="var(--ggui-spacing-2)"
                        borderRadius="var(--ggui-shape-radius-md)"
                        background={avatar === avatarEmoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surface)'}
                        style={{
                          border: avatar === avatarEmoji ? '2px solid var(--ggui-color-primary-600)' : '2px solid var(--ggui-color-outline)',
                          cursor: 'pointer',
                          transition: 'all 200ms ease',
                          fontSize: '32px',
                        }}
                      >
                        {avatarEmoji}
                      </Box>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Stack gap="var(--ggui-spacing-6)">
            <Card shadow="md" padding="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Step 2: Preferences</Heading>
                <Stack gap="var(--ggui-spacing-4)">
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={rolesList}
                    placeholder="Select your role"
                  />

                  <Stack gap="var(--ggui-spacing-2)">
                    <Toggle
                      label="Enable email notifications"
                      checked={emailNotifications}
                      onChange={setEmailNotifications}
                      size="md"
                    />
                  </Stack>

                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Theme Preference</Text>
                    <RadioGroup
                      label=""
                      value={theme}
                      onChange={setTheme}
                      options={[
                        { value: 'light', label: 'Light' },
                        { value: 'dark', label: 'Dark' },
                      ]}
                      direction="horizontal"
                    />
                  </Stack>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Stack gap="var(--ggui-spacing-6)">
            <Card shadow="md" padding="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Step 3: Review & Confirm</Heading>

                <Stack gap="var(--ggui-spacing-4)">
                  <Card shadow="sm" padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)">
                    <Stack gap="var(--ggui-spacing-3)">
                      <Row justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name:</Text>
                        <Text>{name}</Text>
                      </Row>
                      <Divider orientation="horizontal" margin="var(--ggui-spacing-1)" />
                      <Row justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email:</Text>
                        <Text>{email}</Text>
                      </Row>
                      <Divider orientation="horizontal" margin="var(--ggui-spacing-1)" />
                      <Row justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar:</Text>
                        <Text>{avatar}</Text>
                      </Row>
                      <Divider orientation="horizontal" margin="var(--ggui-spacing-1)" />
                      <Row justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Role:</Text>
                        <Text>{role}</Text>
                      </Row>
                      <Divider orientation="horizontal" margin="var(--ggui-spacing-1)" />
                      <Row justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Notifications:</Text>
                        <Badge variant={emailNotifications ? 'success' : 'default'}>
                          {emailNotifications ? 'Enabled' : 'Disabled'}
                        </Badge>
                      </Row>
                      <Divider orientation="horizontal" margin="var(--ggui-spacing-1)" />
                      <Row justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme:</Text>
                        <Text>{theme.charAt(0).toUpperCase() + theme.slice(1)}</Text>
                      </Row>
                    </Stack>
                  </Card>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        )}

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="end">
          {currentStep > 1 && (
            <Button
              variant="secondary"
              onClick={handleBack}
            >
              Go Back
            </Button>
          )}
          {currentStep < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={currentStep === 1 && !isStep1Valid}
            >
              Next
            </Button>
          )}
          {currentStep === 3 && (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
